<!DOCTYPE html>
<html>
<head>
<style>
body {
  background-color: #1a1a2e;
  color: white;
  font-family: Arial, sans-serif;
  margin: 0;
  padding: 20px;
}
#bars {
  display: flex;
  align-items: flex-end;
  height: 400px;
  border: 1px solid #333;
  margin-bottom: 20px;
  width: 100%;
  max-width: 600px;
}
.bar {
  width: 20px;
  margin: 0 2px;
  background-color: #4a90d9;
  transition: height 0.3s, background-color 0.3s;
}
.bar.comparing {
  background-color: #ff6b6b;
}
.bar.sorted {
  background-color: #50c878;
}
button {
  padding: 10px 20px;
  margin-right: 10px;
  background-color: #4a90d9;
  color: white;
  border: none;
  cursor: pointer;
}
button:hover {
  background-color: #333;
}
</style>
</head>
<body>
<div id="bars"></div>
<button id="sort">Sort</button>
<button id="shuffle">Shuffle</button>
<button id="reset">Reset</button>
<script>
const initialArray = [5, 3, 8, 6, 7, 1, 4, 2];

window.viz = {
  _array: [],
  _pass: 0,
  _i: 0,
  _n: 0,
  array() { return this._array; },
  setArray(a) {
    this._array = a;
    this._pass = 0;
    this._i = 0;
    this._n = a.length;
    this._drawBars();
  },
  sortStep() {
    if (this.sorted()) return true;
    const arr = this._array;
    const n = this._n;
    const pass = this._pass;
    const i = this._i;
    const bars = document.querySelectorAll('.bar');
    bars[i].classList.add('comparing');
    bars[i+1].classList.add('comparing');
    if (i < n - pass - 1) {
      if (arr[i] > arr[i+1]) {
        [arr[i], arr[i+1]] = [arr[i+1], arr[i]];
        this._updateBars();
      }
      this._i = i + 1;
    } else {
      this._pass = pass + 1;
      this._i = 0;
    }
    setTimeout(() => {
      bars[i].classList.remove('comparing');
      bars[i+1].classList.remove('comparing');
    }, 300);
    return false;
  },
  sorted() {
    const arr = this._array;
    for (let i = 0; i < arr.length - 1; i++) {
      if (arr[i] > arr[i+1]) return false;
    }
    return true;
  },
  _drawBars() {
    const barsContainer = document.getElementById('bars');
    barsContainer.innerHTML = '';
    const arr = this._array;
    for (let i = 0; i < arr.length; i++) {
      const bar = document.createElement('div');
      bar.className = 'bar';
      bar.style.height = `${arr[i] * 10}px`;
      barsContainer.appendChild(bar);
    }
  },
  _updateBars() {
    const bars = document.querySelectorAll('.bar');
    const arr = this._array;
    for (let i = 0; i < arr.length; i++) {
      bars[i].style.height = `${arr[i] * 10}px`;
    }
  }
};

viz.setArray(initialArray);

document.getElementById('sort').addEventListener('click', () => {
  let step = () => {
    if (viz.sortStep()) {
      // Sorting complete
    } else {
      setTimeout(step, 100);
    }
  };
  step();
});

document.getElementById('shuffle').addEventListener('click', () => {
  const shuffled = viz.array().slice().sort(() => Math.random() - 0.5);
  viz.setArray(shuffled);
});

document.getElementById('reset').addEventListener('click', () => {
  viz.setArray(initialArray);
});
</script>
</body>
</html>
